# lib/my_app_web/xml/safe_parser.ex
defmodule MyAppWeb.XML.SafeParser do
  @moduledoc """
  Secure XML parser that disables external entities to prevent XXE attacks.
  """

  import SweetXml

  @doc """
  Parses XML string safely with external entities disabled.
  Uses xmerl with DTD and external entity processing disabled.
  """
  def safe_parse(xml_string) when is_binary(xml_string) do
    try do
      # Parse with secure options - external entities DISABLED
      doc =
        xml_string
        |> String.to_charlist()
        |> :xmerl_scan.string([
          {:acc_fun, fn x, acc, s -> {[x | acc], s} end},
          # Disable fetching of external entities
          {:fetch_fun, fn _uri, state -> {:ok, {:string, ~c""}, state} end},
          # Disable DTD processing
          {:validation, :off},
          {:quiet, true}
        ])

      case doc do
        {parsed_doc, _rest} ->
          {:ok, parsed_doc}

        _ ->
          {:error, :invalid_xml}
      end
    rescue
      e -> {:error, {:parse_error, Exception.message(e)}}
    catch
      :exit, reason -> {:error, {:parse_error, inspect(reason)}}
    end
  end

  @doc """
  Applies xpath query to a safely parsed XML document.
  """
  def safe_xpath(xml_string, xpath_query) do
    case safe_parse(xml_string) do
      {:ok, doc} ->
        try do
          result = SweetXml.xpath(doc, xpath_query)
          {:ok, result}
        rescue
          e -> {:error, {:xpath_error, Exception.message(e)}}
        end

      {:error, _} = error ->
        error
    end
  end

  @doc """
  Applies xpath with multiple selectors to a safely parsed XML document.
  """
  def safe_xmap(xml_string, selectors) do
    case safe_parse(xml_string) do
      {:ok, doc} ->
        try do
          result = SweetXml.xmap(doc, selectors)
          {:ok, result}
        rescue
          e -> {:error, {:xpath_error, Exception.message(e)}}
        end

      {:error, _} = error ->
        error
    end
  end
end

