defmodule MyAppWeb.SoapController do
  use MyAppWeb, :controller

  import SweetXml, only: [sigil_x: 2]
  alias MyAppWeb.XML.SafeParser

  @doc """
  Handles incoming SOAP requests securely.
  """
  def handle(conn, _params) do
    xml_body = conn.assigns[:raw_xml]

    # Validate input size to prevent XML bomb / billion laughs attack
    max_size = 1_048_576  # 1MB limit

    if byte_size(xml_body) > max_size do
      conn
      |> put_resp_content_type("application/xml")
      |> send_resp(413, soap_fault("Payload too large"))
    else
      process_soap_request(conn, xml_body)
    end
  end

  defp process_soap_request(conn, xml_body) do
    # Safely parse and extract SOAP envelope fields using xpath
    with {:ok, envelope_ns} <- SafeParser.safe_xpath(xml_body, ~x"//Envelope"e),
         {:ok, body_content} <- SafeParser.safe_xpath(xml_body, ~x"//Body/*"e),
         {:ok, data} <-
           SafeParser.safe_xmap(xml_body, %{
             action: ~x"//Body//*[1]"s |> SweetXml.transform_by(&extract_local_name/1),
             params: ~x"//Body//*[1]/*"le
           }) do
      # Process the SOAP action
      action = Map.get(data, :action, "unknown")

      response_xml = build_soap_response(action, data)

      conn
      |> put_resp_content_type("application/xml; charset=utf-8")
      |> send_resp(200, response_xml)
    else
      {:error, reason} ->
        conn
        |> put_resp_content_type("application/xml; charset=utf-8")
        |> send_resp(500, soap_fault("Failed to process request: #{inspect(reason)}"))
    end
  end

  defp extract_local_name(name) when is_binary(name) do
    name
    |> String.split(":")
    |> List.last()
  end

  defp extract_local_name(other), do: to_string(other)

  defp build_soap_response(action, _data) do
    """
    <?xml version="1.0" encoding="UTF-8"?>
    <soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">
      <soap:Body>
        <#{action}Response>
          <Result>Success</Result>
        </#{action}Response>
      </soap:Body>
    </soap:Envelope>
    """
  end

  defp soap_fault(message) do
    """
    <?xml version="1.0" encoding="UTF-8"?>
    <soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">
      <soap:Body>
        <soap:Fault>
          <faultcode>soap:Server</faultcode>
          <faultstring>#{escape_xml(message)}</faultstring>
        </soap:Fault>
      </soap:Body>
    </soap:Envelope>
    """
  end

  defp escape_xml(string) do
    string
    |> String.replace("&", "&amp;")
    |> String.replace("<", "&lt;")
    |> String.replace(">", "&gt;")
    |> String.replace("\"", "&quot;")
    |> String.replace("'", "&apos;")
  end
end